var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"어렸을 때부터 남들과는 조금 다른 취급이었어.","JPN":"小さい頃から他の人たちとは少し違う扱いをされていた。","ENG":"I've always been treated differently ever since I was little.","TWN":"從小，我的處境就跟大家不一樣。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"패밀리의 보스. 아버지를 따르는 사람들에게 있어 나는 하늘과도 같은 존재였거든.","JPN":"ファミリーのボス。お父様に従う人たちにとって、私は天のような存在だったから。","ENG":"Because my father was the boss of the mafia family, everyone under him treated me like royalty.","TWN":"家族的老大，我對爸爸的手下而言，彷彿天一般的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"존경, 시기, 질투… 어린 내게 그런 감정은 사뭇 익숙한 것들이었지.","JPN":"尊敬、嫉妬……小さい私に、そんな感情は結構慣れたものだった。","ENG":"Respect, jealousy, envy... All those emotions were familiar to me even when I was little.","TWN":"尊敬、猜忌、忌妒…這些情緒在我小時候就已經很熟悉。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"그래. 목숨을 위협받는 일도 종종 있었을 정도로.","JPN":"そう。命が脅かされることもたまにあったくらいに。","ENG":"Yeah, even to a point where I would often receive death threats.","TWN":"還有，性命受到威脅也是常有的事。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"여긴…?","JPN":"ここは……？","ENG":"Where am I...?","TWN":"這裡是…？"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"분명… 꼬맹이를 감싸려다… 무언가에 휩쓸려서.","JPN":"確かに……ガキを庇おうとして……何かに巻き込まれて。","ENG":"I was... trying to protect the kid, and... something swept me away.","TWN":"我剛才…原本要護住小鬼…結果被某個東西給捲走。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"그렇다면 여긴, 아티팩트가 만들어낸 공간인가?","JPN":"だったらここは、アーティファクトが作り出した空間なのか？","ENG":"Does that mean that this is a space that the Artifact created?","TWN":"所以這裡是，人造神器創造出來的空間？"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"…뭐야, 이건?","JPN":"……何だ、これは。","ENG":"...What's this?","TWN":"…搞什麼？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"제길. 진짜 저주라도 걸린 건가? 이런 시덥잖은 복장만 하루 종일…","JPN":"くそ。本当に呪われてるのか？　一日中ずっとこんなくだらん服装を……","ENG":"Dammit. Am I really cursed? Why am I wearing this ridiculous outfit all day...","TWN":"該死的，這身衣服是被詛咒嗎？整天陰魂不散的…"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"윽!?","JPN":"うっ！？","ENG":"Ngh?!","TWN":"呃！？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"도망치고 싶다는 생각도 조금은 있었을지도 모르지.","JPN":"逃げたいという心も少しはあったかもしれない。","ENG":"Maybe I thought of wanting to run away a little.","TWN":"或許我心裡也有點想要逃跑的念頭。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"그렇지만 그 이상으로, 가족에 대한 책임감도 있었어.","JPN":"でもそれ以上に、家族への責任感もあった。","ENG":"But more than that, I had a sense of responsibility to my family.","TWN":"話雖如此，但我對家族是有責任的。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"내가 지켜야 할 것이 있었으니까.","JPN":"私が守るべきことがあったから。","ENG":"I had something to protect.","TWN":"我有必須守護的東西。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>넌 아무것도 지키지 못했잖아.</color>","JPN":"<color=#ff3636>お前は何も守れなかっただろう。</color>","ENG":"<color=#ff3636>But you couldn't protect anything.</color>","TWN":"<color=#ff3636>你明明什麼也守護不了。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"그 아이를 데려온 건, 어렸을 때의 나를 투영해서일지도 모르지.","JPN":"あの子を連れてきたのは、小さい頃の私を投影したからかもしれない。","ENG":"Perhaps I brought in that kid because I was projecting myself onto her.","TWN":"我之所以會把她帶在身邊，或許是因為她令我想起小時候的我。"},"stage":{"bg":"OFFICE_DETECT","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>그 아이를 데려온 건, 널 투영할 수 있는 인형이 필요해서야.</color>","JPN":"<color=#ff3636>あの子を連れてきたのは、お前を投影できる人形が必要だからだ。</color>","ENG":"<color=#ff3636>You brought in that kid because you needed a doll to reflect yourself on.</color>","TWN":"<color=#ff3636>你之所以會把她帶在身邊，是因為你需要一個投射的娃娃。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"망가지더라도, <color=#ff3636>인형</color>은 바꾸면 그만이니까.","JPN":"壊れても、<color=#ff3636>人形</color>は替えればいいだけだから。","ENG":"Even if the original breaks, <color=#ff3636>dolls</color> are easily replaceable.","TWN":"反正<color=#ff3636>娃娃</color>壞掉的話，只要再換一個新的就好。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};